// src/pages/Home.js
import React, { useState, useEffect } from 'react';

const Home = () => {
    const [venues, setVenues] = useState([]);
    const [error, setError] = useState(null); // State for managing error messages

    useEffect(() => {
        const fetchVenues = async () => {
            try {
                const response = await fetch('http://localhost:3001/api/venues'); // Adjust the URL if necessary
                if (!response.ok) {
                    throw new Error('Network response was not ok');
                }
                const data = await response.json();
                setVenues(data);
            } catch (error) {
                console.error('Error fetching data:', error);
                setError('Failed to fetch venues. Please try again later.');
            }
        };

        fetchVenues();
    }, []);

    return (
        <div>
            <h1>Welcome to the Venue List</h1>
            {error && <p style={{ color: 'red' }}>{error}</p>} {/* Display error message if any */}
            <table>
                <thead>
                    <tr>
                        <th>Name</th>
                        <th>Location</th>
                        <th>Capacity</th>
                        <th>Contact</th>
                        <th>Notes</th>
                        <th>Parking</th>
                        <th>Accessibility</th>
                        <th>Owner</th>
                        <th>TCUP Rating</th>
                    </tr>
                </thead>
                <tbody>
                    {venues.length > 0 ? (
                        venues.map((venue) => (
                            <tr key={venue.id}>
                                <td>{venue.name}</td>
                                <td>{venue.location}</td>
                                <td>{venue.capacity}</td>
                                <td>
                                    <a href={`mailto:${venue.contact_info}`} target="_blank" rel="noopener noreferrer">
                                        {venue.contact_info}
                                    </a>
                                </td>
                                <td>{venue.notes}</td>
                                <td>{venue.parking}</td>
                                <td>{venue.accessibility}</td>
                                <td>{venue.owner}</td>
                                <td>{venue.tcup_rating}</td>
                            </tr>
                        ))
                    ) : (
        <tr>
            <td colSpan="9">No venues found.</td>
        </tr>
    )}
</tbody>
            </table>
        </div>
    );
};

export default Home;
